    54→export function formatDate(dateStr: string): string {
    55→  const [year, month, day] = dateStr.split('-').map(Number);
    56→  const date = new Date(year, month - 1, day);
    57→  return date.toLocaleDateString('en-US', {
    58→    weekday: 'long',
    59→    year: 'numeric',
    60→    month: 'long',
    61→    day: 'numeric',
    62→  });
    63→}
