/**
 * AI Daily Flash — Newsletter Generator
 *
 * Fetches AI/tech news from RSS feeds, curates with Claude,
 * and saves a structured JSON newsletter to data/newsletters/.
 *
 * Run: node scripts/generate-newsletter.js
 * Env: ANTHROPIC_API_KEY
 */

'use strict';

const Anthropic = require('@anthropic-ai/sdk');
const Parser = require('rss-parser');
const fs = require('fs');
const path = require('path');

// ──────────────────────────────────────────────────────────────
// Config
// ──────────────────────────────────────────────────────────────

// Practitioner voices — blogs, Substacks, personal sites, and GitHub activity
// from people actively building and thinking in AI.
// These are weighted higher in the prompt.
const PRACTITIONER_FEEDS = [
  // ── Karpathy ──────────────────────────────────────────────────
  {
    name: 'Andrej Karpathy',
